<!DOCTYPE html><html lang="en"><head><title>Order Entry</title><style>body{font-family:sans-serif;background:#1a1a2e;color:#eee;padding:2rem}form{background:#16213e;padding:2rem;border-radius:8px;max-width:600px}label{display:block;margin-top:1rem;color:#0f3460}input,select{width:100%;padding:.5rem;background:#1a1a2e;border:1px solid #0f3460;color:#eee;border-radius:4px}button{margin-top:1.5rem;padding:.75rem 2rem;background:#0f3460;color:#fff;border:none;border-radius:4px;cursor:pointer}</style></head><body><h1>📝 Order Entry</h1><form id="orderForm"><label>Customer</label><input type="text" id="customer" placeholder="Search customer..."><label>Product</label><select id="product"><option>Widget A - $49.99</option><option>Widget B - $79.99</option><option>Gadget X - $149.99</option></select><label>Quantity</label><input type="number" id="qty" value="1" min="1"><button type="submit">Create Order</button></form><script>document.getElementById('orderForm').onsubmit=function(e){e.preventDefault();alert('Order created successfully!')}</script></body></html>